head.script:
//-------------------------------------------------------------------------
// PGM명 : 마감등록 (eq_510_01_06b)
// 작성자 : 송정희
// 최초작성일자 : 2026-01-07
//-------------------------------------------------------------------------
scwin.fromDate_YMD = ""; // 작업날짜
scwin.fromDate_YMD = WebSquare.date.getCurrentServerDate("yyyyMMdd");
scwin.G_eqHomeClsCd = "";

scwin.wframeParamData = {}; 
scwin.obj = {};

//-------------------------------------------------------------------------
// onpageload
//-------------------------------------------------------------------------
scwin.onpageload = async function() {
console.log("PGM : 마감등록 (eq_510_01_06b)");    
	const codeOptions = [
        { grpCd : "ZZ205", compID : "lc_homeClsCd",opt :{"range" : "1,EQ"}},     // 사업부문
        { grpCd : "EQ043", compID : "gr_work_pl:planClsCd"},                     // 계획구분 
        { grpCd : "EQ029", compID : "gr_work_pl:outAcctCd"}                      // 출고계정 
    ];
    $c.data.setCommonCode(codeOptions, scwin.callBackCommCode);  

};

scwin.callBackCommCode = function(){

    console.log($c.data.getMemInfo());
    scwin.G_eqHomeClsCd = $c.data.getMemInfo("eqHomeClsCd");  // 사용자소속구분코드   

    lc_homeClsCd.setValue(scwin.G_eqHomeClsCd);
    scwin.f_RetrieveSecond(lc_homeClsCd.getValue());
}

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. onPageLoad 에서 호출 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = async function () { 
    ed_wrkStDt.setValue(scwin.fromDate_YMD); 
}

//-------------------------------------------------------------------------
// 대표정비작업장콤보 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveSecond = function (param1){ 
	dma_wrkPlCd.set("cmd", "retriveFixWrkList");
    dma_wrkPlCd.set("strVal", param1);
    dma_wrkPlCd.set("intVal", "");

    $c.sbm.execute(sbm_wrkPlCd);
}

//-------------------------------------------------------------------------
// 사업부문 클릭 이벤트
//-------------------------------------------------------------------------
scwin.lc_homeClsCd_onviewchange = function (info) {
    var luxIndex = lc_homeClsCd.getValue();
	// 작업장콤보 조회
    scwin.f_RetrieveSecond(luxIndex);
};

//-------------------------------------------------------------------------
// 조회 조건 지우기
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tb_wrk, null);

    //ed_wrkStDt.setValue(scwin.fromDate_YMD); 

    if (scwin.G_eqHomeClsCd = ""){
        lc_homeClsCd.setValue("LO");
    } else {
        lc_homeClsCd.setValue(scwin.G_eqHomeClsCd);
    }    
    scwin.f_RetrieveSecond("LO");
};

//-------------------------------------------------------------------------
// 조회조건Clear 버튼 클릭시
//-------------------------------------------------------------------------	
scwin.btn_Clear_onclick = function (e) {
    scwin.f_FieldClear();
};
//-------------------------------------------------------------------------
// 그리드 높이 늘리기
//-------------------------------------------------------------------------
scwin.f_grdHeiht = function(size) {
	objGrd = "gr_work_pl";
    var objGrd = eval(objGrd);
  	var strHeight = objGrd.style.height ;
  	var intHeight = parseInt(strHeight.replace("px",""));
  	intHeight = intHeight + size;
 	if (intHeight > 0 ) {
  		objGrd.style.height = intHeight + "px";
 	}
}

//-------------------------------------------------------------------------
// 조회버튼 클릭 이벤트
//-------------------------------------------------------------------------
scwin.btn_Search_onclick = function (e) {
    scwin.f_Retrieve();
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {

    if( !await $c.gus.cfValidate([tb_wrk], null, true)) return;
    $c.gus.cfEnableBtnOnly([btn_Create, btn_Delete]);


    dma_search.set("adjmYm", ed_wrkStDt.getValue());
    dma_search.set("fixWrkPlCd", lc_repWrkPlCd.getValue());

    $c.sbm.execute(sbm_master);

    scwin.setWframe();  
};

//-------------------------------------------------------------------------
// iframe호출 (/cm/bc/comnmgnt/closemgnt/zz_640_03_01b.jsp)
//-------------------------------------------------------------------------  
scwin.setWframe = async function() {
    scwin.wframeParamData = { 
        "closeYm" : ed_wrkStDt.getValue(),
        "closeDd" : "00",  
        "wrkNo"   : "EQ01",
        "mgntNo"  : lc_repWrkPlCd.getValue()
    }; 

    scwin.obj = { 
        "dataObject": {
            "type" : "json",
            "name" : "wframeParam",              
            "data" : scwin.wframeParamData
         }
    };

    var ret = await closeLogIframe.setSrc("/ui/cm/bc/comnmgnt/closemgnt/zz_640_03_01b.xml", scwin.obj); 
// SP5에서는 Promise 객체를 return하므로 await 키워드를 붙여야 setSrc호출 이후의 동작이 정상적인 순서로 동작하게 된다.
};

//-------------------------------------------------------------------------
// 엑셀 출력
//-------------------------------------------------------------------------
scwin.f_Excel = async function() {
   if(ds_fix_work_list.getRowCount() == 0) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return;
    }

    let gridColCount = 0;
    for(let i = 0; i < gr_work_pl.getTotalCol(); i++){
        if(gr_work_pl.getColumnVisible(i)==true){
            gridColCount++;
        }
    }

    let str = $c.gus.cfGetFormatStr(ed_wrkStDt.getValue(), "####-##");
    let str1 = $c.gus.cfGetFormatStr(ed_wrkStDt.getValue(), "######");    
    let str2 = lc_homeClsCd.getValue();
    let str3 = lc_repWrkPlCd.getValue();

    let startRowIndex = 0;
    let infoArr = [{
        rowIndex : 0,             // 첫 번째 줄
        colIndex : 0,             // 첫 번째 칸부터
        colSpan : gridColCount,   // 그리드 전체 너비만큼 병합
        rowSpan : 1,
        text : "마감등록",
        textAlign : "center",     //정렬
        fontSize : 12,
        drawBorder : false,        // 테두리
        color : "black",          // 글자색
        backgroundColor : "#ffffff" // 배경색
    },{
        rowIndex : 2,             // 첫 번째 줄
        colIndex : 0,             // 첫 번째 칸부터
        colSpan : gridColCount,   // 그리드 전체 너비만큼 병합
        rowSpan : 1,
        text : "마감년월 ["+ str +"]",
        textAlign : "left",     //정렬
        fontSize : 10,
        drawBorder : false,        // 테두리
        color : "black",          // 글자색
        backgroundColor : "#ffffff" // 배경색
    },{
        rowIndex : 3,             // 첫 번째 줄
        colIndex : 0,             // 첫 번째 칸부터
        colSpan : gridColCount,   // 그리드 전체 너비만큼 병합
        rowSpan : 1,
        text : "사업부문 ["+ str2 +"], 대표정비작업장 ["+ str3 +"] " ,
        textAlign : "left",     //정렬
        fontSize : 10,
        drawBorder : false,        // 테두리
        color : "black",          // 글자색
        backgroundColor : "#ffffff" // 배경색
    }]

    const options = {
        fileName: "마감등록.xlsx",
    //    sheetName: "마감년월" + str1 + "_" + str2+ "_" + str3 ,
        sheetName: "마감등록",
        startRowIndex : 4,        
        startColumnIndex : 0,
        type : 1
    };
    await $c.data.downloadGridViewExcel(gr_work_pl, options, infoArr);
};

//-------------------------------------------------------------------------
// 마감등록버튼 클릭시
//-------------------------------------------------------------------------
scwin.btn_Create_onclick = function (e) {
    scwin.f_Create();
};

//-------------------------------------------------------------------------
// 마감등록
//-------------------------------------------------------------------------
scwin.f_Create = function() {

    $c.gus.cfDisableBtn([btn_Create, btn_Delete]);

    $c.sbm.execute(sbm_Save);
};

//-------------------------------------------------------------------------
// 마감취소 버튼 클릭시
//-------------------------------------------------------------------------	
scwin.btn_Delete_onclick = function (e) {

    scwin.f_Delete();
};

//-------------------------------------------------------------------------
// 마감취소
//-------------------------------------------------------------------------	
scwin.f_Delete = function (){

	$c.gus.cfDisableBtn([btn_Create, btn_Delete]);

    $c.sbm.execute(sbm_Cancel);
};

//-------------------------------------------------------------------------
// 마감내역 ondataload 이벤트
//-------------------------------------------------------------------------	
scwin.ds_fix_work_list_ondataload = function () {
    let rowCnt = ds_fix_work_list.getTotalRow();
    totalRows.setValue(rowCnt);        

    if( rowCnt == 0 ) {
        $c.win.alert("미마감 상태입니다."); 
        return;
    }
	if( rowCnt == 0 ){
        $c.gus.cfDisableBtn([btn_Create, btn_Delete]);
	    if( $c.gus.cfCheckCreateFlag() == true){
	    	$c.gus.cfTurnCreateFlag(false);
	    }else{
	 		$c.gus.cfAlertMsg(MSG_CM_WRN_002);
	    }
       return;
	} 

    if (rowCnt > 0) {
       gr_work_pl.setFocusedCell(0, "planClsCd", true);
    }    
};


scwin.sbm_Save_submitdone = async function (e) {
	$c.gus.cfEnableAllBtn();
    if (e.responseJSON.resultDataSet[0].Code < 0) return; 

    await $c.win.alert( '마감등록 되었습니다' );
    scwin.f_Retrieve();
};

scwin.sbm_Cancel_submitdone = async function (e) {
    $c.gus.cfEnableAllBtn();    
    if (e.responseJSON.resultDataSet[0].Code < 0) return; 

    await $c.win.alert( '마감취소 되었습니다.' );
    scwin.f_Retrieve();
};
